import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom'; // Necesitamos esto para expulsar intrusos

const Inventario = () => {
    const navigate = useNavigate();

    useEffect(() => {
        // Revisamos si el usuario realmente validó su identidad
        const usuarioValido = localStorage.getItem('usuarioLogueado');
        
        if (!usuarioValido) {
            alert("⚠️ Acceso denegado. Por favor inicia sesión.");
            navigate("/"); // Lo mandamos de regreso al login
        }
    }, [navigate]);

    // ... el resto de tu código del inventario
    return (
        <div>
            <h1>📦 Panel de Inventario Seguro</h1>
            {/* Contenido protegido */}
        </div>
    );
};
